#pragma once\n\n#include \"CoreMinimal.h\"\n#include \"GameFramework/Actor.h\"\n#include \"Components/SceneComponent.h\"\n#include \"Engine/StaticMeshActor.h\"\n#include \"Components/StaticMeshComponent.h\"\n#include \"Perf_CullingOptimizer.generated.h\"\n\nUENUM(BlueprintType)\nenum class EPerf_CullingLevel : uint8\n{\n    None        UMETA(DisplayName = \"None\"),\n    Low         UMETA(DisplayName = \"Low\"),\n    Medium      UMETA(DisplayName = \"Medium\"),\n    High        UMETA(DisplayName = \"High\"),\n    Extreme     UMETA(DisplayName = \"Extreme\")\n};\n\nUSTRUCT(BlueprintType)\nstruct FPerf_CullingSettings\n{\n    GENERATED_BODY()\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Culling\")\n    float FrustumCullingDistance = 15000.0f;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Culling\")\n    float OcclusionCullingDistance = 8000.0f;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Culling\")\n    float SmallObjectCullingSize = 50.0f;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Culling\")\n    bool bEnableDistanceCulling = true;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Culling\")\n    bool bEnableOcclusionCulling = true;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Culling\")\n    bool bEnableFrustumCulling = true;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Culling\")\n    float UpdateFrequency = 0.1f;\n\n    FPerf_CullingSettings()\n    {\n        FrustumCullingDistance = 15000.0f;\n        OcclusionCullingDistance = 8000.0f;\n        SmallObjectCullingSize = 50.0f;\n        bEnableDistanceCulling = true;\n        bEnableOcclusionCulling = true;\n        bEnableFrustumCulling = true;\n        UpdateFrequency = 0.1f;\n    }\n};\n\nUSTRUCT(BlueprintType)\nstruct FPerf_CulledObject\n{\n    GENERATED_BODY()\n\n    UPROPERTY(BlueprintReadOnly, Category = \"Culling\")\n    AActor* Actor;\n\n    UPROPERTY(BlueprintReadOnly, Category = \"Culling\")\n    float DistanceToPlayer;\n\n    UPROPERTY(BlueprintReadOnly, Category = \"Culling\")\n    bool bWasCulled;\n\n    UPROPERTY(BlueprintReadOnly, Category = \"Culling\")\n    float CullingTime;\n\n    FPerf_CulledObject()\n    {\n        Actor = nullptr;\n        DistanceToPlayer = 0.0f;\n        bWasCulled = false;\n        CullingTime = 0.0f;\n    }\n};\n\nUCLASS(BlueprintType, Blueprintable)\nclass TRANSPERSONALGAME_API APerf_CullingOptimizer : public AActor\n{\n    GENERATED_BODY()\n\npublic:\n    APerf_CullingOptimizer();\n\nprotected:\n    virtual void BeginPlay() override;\n    virtual void Tick(float DeltaTime) override;\n\n    UPROPERTY(VisibleAnywhere, BlueprintReadOnly, Category = \"Components\")\n    USceneComponent* RootSceneComponent;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Culling Settings\")\n    FPerf_CullingSettings CullingSettings;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Culling Settings\")\n    EPerf_CullingLevel CullingLevel;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Performance\")\n    float TargetFPS = 60.0f;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Performance\")\n    bool bAdaptiveCulling = true;\n\n    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = \"Debug\")\n    bool bShowCullingDebug = false;\n\n    // Culling data\n    UPROPERTY(BlueprintReadOnly, Category = \"Culling Data\")\n    TArray<FPerf_CulledObject> CulledObjects;\n\n    UPROPERTY(BlueprintReadOnly, Category = \"Statistics\")\n    int32 TotalObjectsInScene;\n\n    UPROPERTY(BlueprintReadOnly, Category = \"Statistics\")\n    int32 ObjectsCulled;\n\n    UPROPERTY(BlueprintReadOnly, Category = \"Statistics\")\n    int32 ObjectsVisible;\n\n    UPROPERTY(BlueprintReadOnly, Category = \"Statistics\")\n    float CullingPerformanceGain;\n\nprivate:\n    float UpdateTimer;\n    float LastFrameTime;\n    TArray<AActor*> SceneActors;\n    APawn* PlayerPawn;\n\npublic:\n    UFUNCTION(BlueprintCallable, Category = \"Culling\")\n    void SetCullingLevel(EPerf_CullingLevel NewLevel);\n\n    UFUNCTION(BlueprintCallable, Category = \"Culling\")\n    void UpdateCullingSettings();\n\n    UFUNCTION(BlueprintCallable, Category = \"Culling\")\n    void PerformCullingPass();\n\n    UFUNCTION(BlueprintCallable, Category = \"Culling\")\n    void GatherSceneActors();\n\n    UFUNCTION(BlueprintCallable, Category = \"Culling\")\n    bool ShouldCullActor(AActor* Actor, const FVector& PlayerLocation);\n\n    UFUNCTION(BlueprintCallable, Category = \"Culling\")\n    void CullActor(AActor* Actor, bool bShouldCull);\n\n    UFUNCTION(BlueprintCallable, Category = \"Culling\")\n    void OptimizeForPerformance(float CurrentFPS);\n\n    UFUNCTION(BlueprintPure, Category = \"Culling\")\n    float GetCullingEfficiency() const;\n\n    UFUNCTION(BlueprintPure, Category = \"Culling\")\n    int32 GetVisibleObjectCount() const;\n\n    UFUNCTION(BlueprintPure, Category = \"Culling\")\n    float GetPerformanceGain() const;\n\n    UFUNCTION(BlueprintCallable, Category = \"Debug\")\n    void ToggleCullingDebug();\n\n    UFUNCTION(BlueprintCallable, Category = \"Debug\")\n    void DrawCullingDebugInfo();\n\n    // Distance-based culling\n    UFUNCTION(BlueprintCallable, Category = \"Culling\")\n    bool IsActorInCullingRange(AActor* Actor, const FVector& PlayerLocation, float CullingDistance);\n\n    // Frustum culling\n    UFUNCTION(BlueprintCallable, Category = \"Culling\")\n    bool IsActorInPlayerView(AActor* Actor);\n\n    // Occlusion culling\n    UFUNCTION(BlueprintCallable, Category = \"Culling\")\n    bool IsActorOccluded(AActor* Actor, const FVector& PlayerLocation);\n\n    // Size-based culling\n    UFUNCTION(BlueprintCallable, Category = \"Culling\")\n    bool IsActorTooSmallToCull(AActor* Actor, const FVector& PlayerLocation);\n\n    // Adaptive culling\n    UFUNCTION(BlueprintCallable, Category = \"Culling\")\n    void UpdateAdaptiveCulling(float CurrentFPS);\n\n    UFUNCTION(BlueprintImplementableEvent, Category = \"Culling\")\n    void OnCullingLevelChanged(EPerf_CullingLevel NewLevel);\n\n    UFUNCTION(BlueprintImplementableEvent, Category = \"Culling\")\n    void OnPerformanceImproved(float PerformanceGain);\n\n    UFUNCTION(BlueprintImplementableEvent, Category = \"Culling\")\n    void OnCullingPassCompleted(int32 TotalObjects, int32 CulledObjects);\n};"